class NamedZone(BusinessUnitMixin, OtovoModel):
    if TYPE_CHECKING:
        objects: models.Manager[NamedZone]
        base_markup_rules: RelatedManager[ShoppingCartBaseMarkupRule]
        field_sales_schedules: RelatedManager[FieldSalesSchedule]
        replaced_by: NullableForeignKey[NamedZone]

    name = models.TextField(null=False)
    polygon = MultiPolygonField(null=False, geography=True, db_index=True)

    # For tracking updates to polygons
    replaces = OneToOneOrNoneField(
        'self',
        on_delete=models.PROTECT,
        blank=True,
        null=True,
        related_name='replaced_by',
    )

    def __str__(self) -> str:
        return self.name

    @classmethod
    def all_heads(cls) -> models.QuerySet[NamedZone]:
        return cls.objects.exclude(Exists(cls.objects.filter(replaces=models.OuterRef('id'))))

    @classmethod
    def all_heads_for_user(cls, user: OtovoUser) -> models.QuerySet[NamedZone]:
        return cls.all_heads().filter(business_unit__in=BusinessUnit.all_for_user(user))

    def get_edit_url(self) -> str:
        current = self
        while current.replaced_by is not None:
            current = current.replaced_by
        return f'{reverse("location:zone-create")}?replaces={current.id}'


class CountyPolygon(OtovoModel):
    """
    This model stores the polygon of a County.
    A CountyPolygon can span a large area, and has many vertices.
    Avoid point in polygon lookups on CountyPolygon because they will simply take too long.
    Instead, do point in polygon lookups on SubDividedCountyPolygon.

    Upon save, a task to sub divide the new polygon will be triggered.
    """

    polygon = MultiPolygonField(geography=True)


class MunicipalityPolygon(OtovoModel):
    """
    This model stores the polygon of a municipality.
    A MunicipalityPolygon can span a large area, and has many vertices.
    Avoid point in polygon lookups on MunicipalityPolygon because they will simply take too long.
    Instead, do point in polygon lookups on SubDividedMunicipalityPolygon.

    Upon save, a task to sub divide the new polygon will be triggered.
    """

    polygon = MultiPolygonField(geography=True)


class SubDividedCountyPolygon(OtovoModel):
    """
    This model stores the breakdown of one county polygon to many smaller,
    simpler polygons with less vertices. This allows us to significantly
    speed up point in polygon lookups.
    """

    polygon = MultiPolygonField(geography=True)
    county = models.ForeignKey(
        'location.County',
        on_delete=models.PROTECT,
        related_name='subdividedcountypolygon_set',
    )

    class Meta:
        indexes = [GistIndex(fields=['polygon'])]


class SubDividedMunicipalityPolygon(OtovoModel):
    """
    This model stores the breakdown of one municipality polygon to many smaller,
    simpler polygons with less vertices. This allows us to significantly
    speed up point in polygon lookups.
    """

    polygon = MultiPolygonField(geography=True)
    municipality = models.ForeignKey(
        'location.Municipality',
        on_delete=models.PROTECT,
        related_name='subdividedmunicipalitypolygon_set',
    )

    class Meta:
        indexes = [GistIndex(fields=['polygon'])]


