class ZipCode(OtovoModel):
    code = models.CharField(max_length=8, validators=[validators.RegexValidator(regex=r'^\d{4,8}$')])
    name = models.CharField(max_length=50)
    country = EnumCharField(enum=Country, default=Country.NO, max_length=2)
    municipalities = models.ManyToManyField('location.Municipality')

    def validate_code(self):
        if not self.code:
            return False
        if self.country == Country.NO:
            return len(self.code) == 4
        if self.country == Country.SE:
            return len(self.code) == 5
        return True

    class Meta(OtovoModel.Meta):
        unique_together = ('code', 'country')
        ordering = ('code',)

    def __str__(self):
        if self.country == Country.SE:
            return f'{self.code[:3]} {self.code[3:]} {self.name}'
        if self.country == Country.BR:
            return f'{self.code[:5]}-{self.code[5:]}'
        if self.country == Country.PL:
            return f'{self.code[:2]}-{self.code[2:]}'
        if self.name == self.code or not self.name:
            return f'{self.code}'
        else:
            return f'{self.code} {self.name}'

    @transaction.atomic
    def save(self, *args, **kwargs):
        if not self.validate_code():
            raise Exception('Invalid zip code format')
        return super().save()


