    @classmethod
    def all_for_staff_user(cls, user):
        if not user.has_perm('location.view_address'):
            return cls.objects.none()

        return cls.objects.all()

    def get_address_info(self):
        data = {}
        for key, value in self.extra_data.items():
            with suppress(ValueError):
                data[AddressInfo(key)] = value
                short_value = self.extra_data.get(key + '_SHORT_NAME')
                if short_value and short_value != value:
                    data[AddressInfo(key)] = value = f'{value} ({short_value})'
        return data

    def get_extra_data(self, key):
        key = str(key)
        return self.extra_data.get(key)

    def set_extra_data(self, *, key, value):
        self.extra_data[str(key)] = value
        self.save()

    def get_surfaces(self, *, include_custom_surfaces=False):
        if include_custom_surfaces:
            return self.surface_set.all().select_related('address')
        return self.surface_set.filter(interest=None).select_related('address')

    def get_absolute_url(self):
        return '{}{}'.format(
            settings.CLOUD_URL,
            reverse('location:address-detail', urlconf='cloud.urls', args=[self.id]),
        )

    def refresh_from_cadastre(self, blocking=True, force=False):
        if not force and self.refreshed_at and self.refreshed_at > timezone.now() - timedelta(hours=1):
            logger.debug(f'Skipping refresh of recently refreshed address {self}')
            return
        if not blocking:
            from cloud.location.tasks import refresh_from_cadastre

            return refresh_from_cadastre.delay(self.pk)

        assert self.provider != AddressProvider.UNKNOWN, 'Cannot refresh address with provider UNKNOWN'

        if self.provider == AddressProvider.MANUAL:
            logger.debug('Skipping refresh of manually created address')
            return
        elif self.provider == AddressProvider.BAN_FR:
            logger.debug('Skipping refresh of BAN address')
            return
        elif self.provider == AddressProvider.NORKART:
            from cloud.location.providers import norkart

            try:
                norkart.refresh_from_cadastre_address_api(self)
                norkart.refresh_from_cadastre_unit_api(self)
            except Exception:
                # Norkart is not quite done with the 2020
                # changes, so we refresh what we can.
                sentry_sdk.capture_exception()

        elif self.provider == AddressProvider.OPTIWAY:
            logger.debug('Skipping refresh of Optiway address')
            return
        elif self.provider == AddressProvider.GOOGLE or self.provider == AddressProvider.SWISSTOPO:
            from cloud.location.providers import google

            google.refresh_from_cadastre_unit_id(self)

        self.refreshed_at = timezone.now()
        self.save()

    def refresh_surfaces(self, blocking=True):
        if not blocking:
            from cloud.location.tasks import refresh_surfaces

            return refresh_surfaces.delay(self.pk)

        from cloud.surfaces.models import Building, Surface

        buildings = Building.fetch_buildings_for_address(self)
        refresh_surface_list = []

        for building in buildings:
            for surface in building.surface_set.select_related('address').all():
                refresh_surface_list.append(surface)

        for surface in self.get_surfaces(include_custom_surfaces=True):
            if surface not in refresh_surface_list:
                refresh_surface_list.append(surface)

        if not refresh_surface_list:
            return

        if len(refresh_surface_list) > 50:
            raise TooManySurfacesException(f'Unable to refresh surfaces for address {self.id}')

        yields = get_yields(refresh_surface_list)

        update_fields = {'updated_at', 'energy_yield', 'monthly_energy_yield'}
        surfaces = []
        for surface, yield_result in yields:
            surface.updated_at = timezone.now()
            surface.energy_yield = yield_result.yearly
            surface.monthly_energy_yield = yield_result.monthly
            update_fields |= surface.set_score()  # this has side effects
            surfaces.append(surface)
        Surface.objects.bulk_update(surfaces, list(update_fields))

    def fetch_cadastral_address_id(self):
        if self.cadastral_address_id:
            return

        # attempt to calculate the cadastral address ID if empty
        cadastral_address = None
        if self.point:
            cadastral_address = get_cadastral_id(self)

        if cadastral_address is not None:
            self.cadastral_address_id = cadastral_address

            try:
                self.save()
            except IntegrityError as exc:
                logger.exception('Unable to fetch address id for %s: %s', self.id, exc)

    @classmethod
