        return cls.objects.filter(country=Country.ES)

    @property
    def is_exact_address(self) -> bool:
        perimeter = self.get_bounding_box_perimeter_in_meters()
        if perimeter:
            # If the perimeter is less than 8km long, we consider the address "exact"
            # An exact address is a pinned address, or an address with enough detail
            # that no pinning was required (e.g., Torgata 7, Oslo)
            # An approximate address is an area address that was searched (e.g, Oslo)
            return perimeter < 8000
        # Only addresses sourced from Google have bounding box.
        # Addresses sourced from other providers are therefore all exact.
        return True

