    def get_sunrise(self, date):
        if not self.point:
            return
        try:
            from astral.location import Location, LocationInfo

            longitude, latitude = self.point
            location = Location(
                LocationInfo(
                    name='',
                    region='',
                    timezone=self.timezone,
                    latitude=float(latitude),
                    longitude=float(longitude),
                )
            )
            return location.sunrise(date=date)
        except ValueError as exc:
            logger.exception(exc)
            return

    def get_sunset(self, date):
        if not self.point:
            return
        try:
            from astral.location import Location, LocationInfo

            longitude, latitude = self.point
            location = Location(
                LocationInfo(
                    name='',
                    region='',
                    timezone=self.timezone,
                    latitude=float(latitude),
                    longitude=float(longitude),
                )
            )
            return location.sunset(date=date)
        except ValueError as exc:
            logger.exception(exc)
            return

