    def get_snow_load(self):
        from cloud.snowload.models import SnowLoad as SnowLoadService

        result = SnowLoadService.get_snow_load(address=self)
        if result is None:
            return Decimal('1.0')
        return result

    def get_other_addresses_on_same_cadastral_unit(self):
        return Address.objects.filter(cadastral_unit_id=self.cadastral_unit_id, country=self.country).exclude(
            pk=self.id
        )

    def get_bounding_box_as_polygon(self) -> list[dict[str, float]] | None:
        if not self.bounding_box:
            return None

        min_lng, min_lat, max_lng, max_lat = self.bounding_box
        return [
            {
                'lng': min_lng,
                'lat': min_lat,  # northwest
            },
            {
                'lng': min_lng,
                'lat': max_lat,  # southwest
            },
            {
                'lng': max_lng,
                'lat': max_lat,  # southeast
            },
            {
                'lng': max_lng,
                'lat': min_lat,  # northeast
            },
            {
                'lng': min_lng,
                'lat': min_lat,  # northwest
            },
        ]

    def get_bounding_box_perimeter_in_meters(self) -> float | None:
        if not self.bounding_box:
            return None

        polygon = self.get_bounding_box_as_polygon()
        geod = CRS.from_epsg(SRID.SRID_4326).get_geod()

        if not geod or not polygon:
            return None

        _, perimeter_in_m = geod.polygon_area_perimeter(
            lons=[point['lng'] for point in polygon],
            lats=[point['lat'] for point in polygon],
        )
        return perimeter_in_m
