def get_locations_map_data(projects, installations):
    cache_key = 'locations_map_data'
    cached = cache.get(cache_key)
    if cached:
        return cached

    installation_template = get_template('location/installation_info_window.html')
    project_template = get_template('location/project_info_window.html')

    def get_address_context(address, with_title=True):
        longitude, latitude = address.point
        if with_title:
            return {
                'position': {
                    'lat': float(latitude),
                    'lng': float(longitude),
                },
                'title': str(address),
            }
        else:
            return {
                'position': {
                    'lat': float(latitude),
                    'lng': float(longitude),
                },
                'title': '',
            }

    def get_installation_context(installation):
        return {
            'type': 'Installation',
            'url': installation.get_absolute_url(),
            'installation_date': installation.installation_date,
            'nominal_system_power_in_kwp': (installation.nominal_system_power_in_kwp),
        }

    def get_project_context(project):
        return {
            'type': 'Project',
            'url': project.get_absolute_url(),
            'created_at': project.created_at,
            'nominal_system_power_in_kwp': (project.nominal_system_power_in_kwp),
        }

    seen_addresses = set()
    locations = []

    for obj in list(installations) + list(projects):
        address = obj.address
        if not (address and address.point):
            continue

        if address.id in seen_addresses:
            continue
        seen_addresses.add(address.id)

        loc = get_address_context(address)

        if obj.__class__.__name__ == 'Installation':
            loc.update(get_installation_context(obj))
            loc['content'] = installation_template.render(loc)
        elif obj.__class__.__name__ == 'Project':
            loc.update(get_project_context(obj))
            loc['content'] = project_template.render(loc)

        locations.append(loc)

    locations = json.dumps(locations, cls=JinjaJSONEncoder)
    cache.set(cache_key, locations, 3600)

    return locations


