class UpdateSpanishCadastralAddressID(GenericAPIView, StaffRequiredMixin):
    serializer_class = AddressSerializer
    model = Address
    object: Address | None = None
    form_class = UpdateSpanishCadastralAddressIdForm

    if TYPE_CHECKING:

        def get_object(self, queryset=None) -> Address: ...

    def post(self, request, *args, **kwargs):
        form = UpdateSpanishCadastralAddressIdForm(request.POST)

        if not form.is_valid():
            return HttpResponseBadRequest('Invalid cadastral ID')

        address = self.get_object()

        if address.country != Country.ES:
            return HttpResponseBadRequest('Cadastral ID update is only available for addresses in Spain')

        serializer = self.get_serializer(data=request.data, partial=True)
        serializer.is_valid(raise_exception=True)

        request_cadastral_id = serializer.validated_data.get('cadastral_address_id')
        address.cadastral_address_id = request_cadastral_id

        try:
            address.save()
        except IntegrityError:
            sentry_sdk.capture_exception()
            return HttpResponse(status=status.HTTP_409_CONFLICT)

        return HttpResponse(status=status.HTTP_204_NO_CONTENT)

    def get_queryset(self):
        return Address.all_es_addresses(self.request.user)


class RefreshSpanishCadastralAddressID(GenericAPIView, StaffRequiredMixin):
    def get(self, request, *args, **kwargs):
        address = self.get_object()

        if address.country != Country.ES:
            return HttpResponseBadRequest('Cadastral ID update is only available for addresses in Spain')

        if address.cadastral_address_id:
            return HttpResponse(status=status.HTTP_204_NO_CONTENT)

        address.fetch_cadastral_address_id()

        if address.cadastral_address_id:
            messages.success(request, 'Cadastral ID successfully fetched.')
        else:
            messages.error(
                request,
                'Cadastral Id cannot be fetched. Please enter it manually using Sedecatastro map service.',
            )

        next_url = self.request.GET.get('next')
        if next_url:
            return redirect(next_url)

        return redirect(address)

    def get_queryset(self):
        return Address.all_es_addresses(self.request.user)


class CoverageMapLodApi(OtovoPermissionRequiredMixin, mixins.RetrieveModelMixin, APIView):
    permission_required = 'installers.installeruser_act_as_admin'
    permission_classes = (permissions.IsAuthenticated,)

    def get(self, request, *args, **kwargs):
        installer_id = kwargs.get('installer_pk')
        bbox_string = request.GET['bbox']
        zoom_level = int(request.GET['z'])
        lod_degrees = 0.75 / (1 << zoom_level)

        installer = None
        municipality_zoom_limit = 6
        if installer_id:
            installer = Installer.objects.get(id=installer_id)
            municipality_zoom_limit = installer.business_unit.config.municipality_zoom_level
        municipality_view = zoom_level > municipality_zoom_limit

        cme_table = CostModelCoverageExpansion._meta.db_table
        if municipality_view:
            object_table = Municipality._meta.db_table
            object_polygon_table = MunicipalityPolygon._meta.db_table
            cmc_table = 'municipality'
            cme_column = 'municipality'
        else:
            object_table = County._meta.db_table
            object_polygon_table = CountyPolygon._meta.db_table
            cmc_table = 'county'
            cme_column = 'counties'
        with connection.cursor() as cursor:
            if installer_id and installer:
                args = [
                    municipality_view,
                    lod_degrees,
                    installer_id,
                    *bbox_string.split(','),
                    installer.country.value,
                ]
            else:
                args = [municipality_view, lod_degrees, *bbox_string.split(',')]

            cursor.execute(
                f"""
SELECT
    JSON_BUILD_OBJECT(
        'type', 'FeatureCollection',
        'features',
            COALESCE(JSON_AGG(
                JSON_BUILD_OBJECT(
                    'type', 'Feature',
                    'properties', JSON_BUILD_OBJECT(
                        'id', id,
                        'country', country,
                        'code', code,
                        'name', name,
                        'partial', partial,
                        'is_municipality', %s,
                        'cm_active', cm_active,
                        'prospects', prospects
                    ),
                    'geometry', geom
                )
            ), JSON_BUILD_ARRAY())
    )
FROM
  (
    SELECT
      m.id,
      m.country,
      m.code,
      m.name,
      coverage.partial,
      coverage.cm_active,
      COALESCE(expansion.prospects::int, -1) AS prospects,
      ST_AsGeoJSON(
        ST_SimplifyPreserveTopology(polygon::geometry, %s)
      )::JSON AS geom
    FROM {object_table} m
    JOIN {object_polygon_table} mp ON (mp.id = m.area_id)
    LEFT JOIN (
        SELECT
            cmc.{cmc_table}_id AS id,
            partial AS partial,
            {'ARRAY_AGG(DISTINCT cm.name)' if installer_id else 'COUNT(cm.id)'}  AS cm_active,
            {'1' if municipality_view else '0'}::bool AS is_municipality
        FROM installercost_costmodelpolygon{cmc_table}coverage cmc
        JOIN installercost_costmodel cm ON (cm.id = cmc.costmodel_id)
        WHERE cm.status = 'published'
        {'AND cm.installer_id = %s' if installer_id else ''}
        GROUP BY 1,2
        ) AS coverage ON (coverage.id = m.id)
    LEFT JOIN (
        WITH expansion_unfloded as
            (
                SELECT
                    DISTINCT ON (country) country,
                    interest_number_by_{cme_column} as data
                FROM {cme_table}
                ORDER BY
                    country,
                    updated_at DESC
            )
        SELECT
            expansion_unfloded.country,
            key::uuid as location_id,
            value as prospects
        FROM expansion_unfloded, jsonb_each(expansion_unfloded.data)
        ) as expansion ON (expansion.location_id = m.id)
    WHERE mp.polygon && ST_MakeEnvelope(%s, %s, %s, %s, 4326) {'AND m.country = %s' if installer_id else ''}
  ) AS q
            """,
                args,
            )

            (geojson,) = cursor.fetchone()

            response = HttpResponse(json.dumps(geojson), content_type='application/json')

            return compress_response(response)


