        with connection.cursor() as cursor:
            cursor.execute(
                f"""
                SELECT
                   JSON_AGG(JSON_BUILD_OBJECT(
                        'type', 'Feature',
                        'properties', JSON_BUILD_OBJECT(
                            'id', m.id,
                            'country', m.country,
                            'county_id', county_id,
                            'county_name', location_county.name,
                            'code', m.code,
                            'name', m.name
                        ),
                        'geometry', ST_AsGeoJSON(ST_SimplifyPreserveTopology(polygon::geometry, 0.01))::JSON
                    ))
                    FROM location_municipality m
                    JOIN location_municipalitypolygon mp ON (mp.id = m.area_id)
                    LEFT JOIN  location_county ON (m.county_id = location_county.id)
                    WHERE m.county_id= '{admin_area_parent_id}'
                """,
            )

            (geojson,) = cursor.fetchone()

            response = HttpResponse(json.dumps(geojson), content_type='application/json')

            return compress_response(response)


