class NamedZoneCreateView(OtovoPermissionRequiredMixin, StaffRequiredMixin, CreateView):
    model = NamedZone
    form_class = NamedZoneForm
    template_name = 'location/namedzone_form.html'
    permission_required = 'location.add_namedzone'
    replaces: NamedZone | None = None

    def dispatch(self, request, *args, **kwargs):
        if replaces_id := request.GET.get('replaces'):
            self.replaces = get_object_or_404(NamedZone, id=replaces_id)
            if self.replaces.replaced_by:
                messages.info(
                    request,
                    'The zone you attempted to edit is replaced, redirected you to the latest version of the zone.',
                )
                return redirect(self.replaces.get_edit_url())
        return super().dispatch(request, *args, **kwargs)

    @cached_property
    def related_field_sales_schedules(self) -> QuerySet[FieldSalesSchedule]:
        if not self.replaces:
            return FieldSalesSchedule.objects.none()
        return self.replaces.field_sales_schedules.select_related('agent__user__profile').filter(
            active_period__contains=timezone.now()
        )

    @transaction.atomic
    def form_valid(self, form: NamedZoneForm):
        named_zone: NamedZone = form.save(commit=False)

        if self.replaces:
            named_zone.replaces = self.replaces

        named_zone.save()
        now = timezone.now()

        schedules_to_update: QuerySet[FieldSalesSchedule] = form.cleaned_data['schedules_to_update']
        for schedule in schedules_to_update:
            # End schedule
            schedule.active_period = DateTimeTZRange(schedule.active_period.lower, now, '[)')
            schedule.save(update_fields=['active_period', 'updated_at'])

            # Create new schedule from the old one, with the new zone
            schedule.pk = None
            schedule.active_period = DateTimeTZRange(now, None, '[)')
            schedule.named_zone = named_zone
            schedule.created_at = now
            schedule.updated_at = now
            schedule.save()

        messages.success(self.request, 'Zone successfully saved')
        return redirect(reverse('location:zones'))

    def form_invalid(self, form: NamedZoneForm):
        if polygon_error := form.errors.get('polygon'):
            messages.error(self.request, polygon_error.as_ul(), extra_tags='safe')
        return super().form_invalid(form)

    def get_form_kwargs(self):
        kwargs = super().get_form_kwargs()
        kwargs['replaces'] = self.replaces
        if self.replaces:
            kwargs['disabled_fields'] = ['name', 'business_unit']
        kwargs['custom_queryset'] = [
            ('business_unit', BusinessUnit.all_for_user(self.request.user, only_central_units=True)),
            ('schedules_to_update', self.related_field_sales_schedules),
        ]
        return kwargs

    def get_context_data(self, **kwargs: Any) -> dict[str, Any]:
        context = super().get_context_data(**kwargs)
        context['has_related_schedules'] = self.related_field_sales_schedules.exists()
        return context
